  ('نه بابا', 'na bâbâ', 'Ach was! / Nein wirklich?', 605, 'نه بابا! واقعاً این‌طور شد؟', 'Ach was! Ist das wirklich so passiert?', NULL, 4),
  ('هر چی تو بگی', 'har chi to begi', 'Wie du meinst', 605, 'باشه، هر چی تو بگی.', 'Okay, wie du meinst.', NULL, 4),
  ('همینطوره', 'hamintore', 'Genau so ist es', 605, 'بله، همینطوره.', 'Ja, genau so ist es.', NULL, 4),
  ('همینه دیگه', 'hamine dige', 'Das ist halt so', 605, 'زندگی همینه دیگه.', 'So ist das Leben halt.', NULL, 4),
  ('هنوز نه', 'hanuz na', 'Noch nicht', 605, 'ـ تمام شد؟ ـ هنوز نه.', '– Fertig? – Noch nicht.', NULL, 4),
  ('ول کن بابا', 'vel kon bâbâ', 'Lass es / Hör auf', 605, 'ول کن بابا، ارزشش را ندارد.', 'Lass es doch, das ist es nicht wert.', NULL, 4),
  ('ولش کن', 'velesh kon', 'Lass ihn/es', 605, 'ولش کن، خودش درست می‌شود.', 'Lass es, das regelt sich von selbst.', NULL, 4),
  ('ولم کن بابا', 'velam kon bâbâ', 'Lass mich in Ruhe', 605, 'خسته‌ام، ولم کن بابا.', 'Ich bin müde, lass mich in Ruhe.', NULL, 4),
  ('چه بخوای', 'che bekhây', 'Was auch immer du willst', 605, 'چه بخوای انجامش می‌دهم.', 'Was auch immer du willst, ich tue es.', NULL, 4),
  ('چه عجب', 'che ajab', 'Na endlich!', 605, 'چه عجب! بالاخره آمدی.', 'Na endlich! Du bist ja doch gekommen.', NULL, 4),
  ('چه نخوای', 'che nakhây', 'Was du nicht willst', 605, 'چه نخوای هم باید قبول کنی.', 'Auch was du nicht willst, musst du akzeptieren.', NULL, 4),
  ('چون', 'chun', 'weil', 605, 'نیامدم چون مریض بودم.', 'Ich kam nicht, weil ich krank war.', NULL, 4),
  ('چونکه', 'chunke', 'weil / da', 605, 'خوشحالم چونکه تو اینجایی.', 'Ich bin froh, weil du hier bist.', NULL, 4),
  ('چی بگم', 'chi begam', 'Was soll ich sagen', 605, 'چی بگم، واقعاً متأسفم.', 'Was soll ich sagen, es tut mir wirklich leid.', NULL, 4),
  ('چی شده', 'chi shode', 'Was ist passiert?', 605, 'چی شده؟ چرا ناراحتی؟', 'Was ist passiert? Warum bist du traurig?', NULL, 4),
  ('کاری نداره', 'kâri nadâre', 'Kein Problem / easy', 605, 'این کار اصلاً کاری نداره.', 'Das ist überhaupt nicht schwer.', NULL, 4),
  ('کاری نداری', 'kâri nadâri', 'Sonst noch was? (Tel.-Abschied)', 605, 'خب، من رفتم؛ کاری نداری؟', 'Also, ich gehe dann; brauchst du sonst noch was?', NULL, 4),
  ('یک بار دیگه', 'yek bâr-e dige', 'Noch einmal', 605, 'یک بار دیگه توضیح بده.', 'Erklär es noch einmal.', NULL, 4),
