  ('حالتو می‌گیرم', 'hâleto migiram', 'Ich mach dich fertig', 606, 'شوخی‌شوخی گفت «حالتو می‌گیرم»، بعد خندیدیم.', 'Scherzhaft sagte er „dir zeig ich''s", dann lachten wir.', NULL, 4),
  ('حالم گرفته', 'hâlam gerefte', 'Ich bin schlecht drauf', 606, 'از این خبر حالم گرفته.', 'Diese Nachricht hat mich schlecht drauf gemacht.', NULL, 4),
  ('حوصله ندارم', 'hosele nadâram', 'Ich hab keine Lust', 606, 'امروز اصلاً حوصله ندارم.', 'Heute habe ich überhaupt keine Lust.', NULL, 4),
  ('خستمه', 'khastame', 'Ich bin müde', 606, 'خیلی کار کردم، خستمه.', 'Ich habe viel gearbeitet, ich bin müde.', NULL, 4),
  ('خوشمزس', 'khoshmazas', 'Es ist lecker', 606, 'این غذا خیلی خوشمزس.', 'Dieses Essen ist sehr lecker.', NULL, 4),
  ('دلم گرفته', 'delam gerefte', 'Ich bin bedrückt', 606, 'امروز دلم گرفته.', 'Heute bin ich bedrückt.', 'wörtl. „Mein Herz ist beklommen“', 4),
  ('سردمه', 'sardame', 'Mir ist kalt', 606, 'پنجره را ببند، سردمه.', 'Mach das Fenster zu, mir ist kalt.', NULL, 4),
  ('سرم شلوغه', 'saram sholughe', 'Ich hab viel zu tun', 606, 'این هفته خیلی سرم شلوغه.', 'Diese Woche habe ich sehr viel zu tun.', 'wörtl. „Mein Kopf ist voll“', 4),
  ('شکمو', 'shekamu', 'Verfressen / Vielfraß', 606, 'برادرم خیلی شکمو است.', 'Mein Bruder ist ein richtiger Vielfraß.', NULL, 4),
  ('عمراً', 'omran', 'Niemals / Auf keinen Fall', 606, 'عمراً دیگر آنجا بروم.', 'Niemals gehe ich da nochmal hin.', NULL, 4),
  ('هیچی', 'hichi', 'Nichts', 606, 'ـ چی شده؟ ـ هیچی، مهم نیست.', '– Was ist los? – Nichts, nicht wichtig.', NULL, 4),
  ('گرسنمه', 'gorosname', 'Ich bin hungrig', 606, 'بریم ناهار، گرسنمه.', 'Lass uns Mittag essen, ich bin hungrig.', NULL, 4),
  ('گرممه', 'garmame', 'Mir ist warm', 606, 'کولر را روشن کن، گرممه.', 'Mach die Klimaanlage an, mir ist warm.', NULL, 4),
  ('گشنمه', 'goshname', 'Ich hab Hunger', 606, 'از صبح چیزی نخوردم، گشنمه.', 'Ich habe seit dem Morgen nichts gegessen, ich habe Hunger.', NULL, 4),
  -- L607
  ('آشغال', 'âshghâl', 'Müll / Abschaum', 607, 'گفتن «آشغال» به یک نفر سخت توهین‌آمیز است.', 'Jemanden „Abschaum" zu nennen ist schwer beleidigend.', NULL, 3),
  ('احمق', 'ahmagh', 'Dummkopf', 607, 'به‌جای «احمق» بهتر است محترمانه صحبت کنیم.', 'Statt „Dummkopf" sprechen wir besser respektvoll.', NULL, 3),
  ('برو پی کارت', 'boro pey-e kâret', 'Kümmer dich um deine Sachen', 607, '«برو پی کارت» یعنی دست از سر کسی بردار، ولی لحنش تند است.', '„Kümmer dich um deine Sachen" heißt, jemanden in Ruhe zu lassen, klingt aber schroff.', NULL, 3),
  ('به تو مربوط نیست', 'be to marbut nist', 'Das geht dich nichts an', 607, 'به‌جای «به تو مربوط نیست» می‌توان مؤدب‌تر پاسخ داد.', 'Statt „das geht dich nichts an" kann man höflicher antworten.', NULL, 3),
  ('به تو چه', 'be to che', 'Was geht''s dich an?', 607, 'مؤدبانه نیست که بگویی «به تو چه».', 'Es ist unhöflich zu sagen „Was geht''s dich an".', NULL, 3),
  ('بی عرضه', 'bi orze', 'Versager / unfähig', 607, 'به کسی نگو بی‌عرضه؛ این توهین است.', 'Nenn niemanden „unfähig"; das ist eine Beleidigung.', NULL, 3),
  ('بی وجدان', 'bi vejdân', 'Gewissenlos', 607, '«بی‌وجدان» خواندن دیگران توهین است.', 'Andere „gewissenlos" zu nennen ist eine Beleidigung.', NULL, 3),
  ('تو گه می‌خوری', 'to goh mikhori', 'du laberst Mist', 607, 'این جمله یک دشنام بسیار زشت است.', 'Dieser Satz ist eine sehr vulgäre Beschimpfung.', 'sehr vulgär', 3),
  ('خاک بر سرت', 'khâk bar saret', 'Schande über dich', 607, '«خاک بر سرت» نفرینی رایج اما بسیار توهین‌آمیز است.', '„Schande über dich" ist ein gängiger, aber sehr beleidigender Fluch.', 'wörtl. „Erde auf deinen Kopf“', 3),
  ('خر', 'khar', 'Esel', 607, '«خر» در مقام دشنام یعنی نادان، و توهین‌آمیز است.', '„Esel" als Schimpfwort bedeutet „dumm" und ist beleidigend.', NULL, 3),
  ('خفه شو', 'khafe sho', 'Halt den Mund', 607, '«خفه شو» بسیار بی‌ادبانه است؛ بهتر است گفته نشود.', '„Halt den Mund" ist sehr unhöflich; besser nicht sagen.', NULL, 3),
  ('دهنت رو ببند', 'dahanet ro beband', 'Halt den Mund', 607, 'این عبارت پرخاشگرانه است و بهتر است از آن پرهیز شود.', 'Dieser Ausdruck ist aggressiv und sollte vermieden werden.', 'wörtl. „Schließ deinen Mund“', 3),
  ('دیوث', 'deyus', 'schwere Beleidigung (Zuhälter/Hahnrei)', 607, 'این کلمه دشنامی بسیار رکیک است و کاربردش پسندیده نیست.', 'Dieses Wort ist eine sehr vulgäre Beschimpfung und sollte nicht verwendet werden.', 'sehr vulgär', 3),
  ('زهر مار', 'zahr-e mâr', 'Halt den Mund!', 607, '«زهر مار» واکنشی خشن و بی‌ادبانه است.', '„Halt den Mund" (wörtl. „Schlangengift") ist eine grobe, unhöfliche Reaktion.', 'wörtl. „Schlangengift“', 3),
  ('غلط کردی', 'ghalat kardi', 'Du hast Mist gebaut', 607, '«غلط کردی» لحنی بسیار تند و تحقیرآمیز دارد.', '„Du hast Mist gebaut" hat einen sehr scharfen, herabsetzenden Ton.', NULL, 3),
  ('مرتیکه الاغ', 'martike olâgh', 'Du Esel', 607, '«مرتیکه الاغ» ناسزایی رایج است و بهتر است گفته نشود.', '„Du Esel" ist ein gängiges Schimpfwort und sollte vermieden werden.', NULL, 3),
  ('مرتیکه خر', 'martike khar', 'Du Esel', 607, 'این عبارت توهین‌آمیز است؛ از آن استفاده نکن.', 'Dieser Ausdruck ist beleidigend; benutze ihn nicht.', NULL, 3),
  ('مرتیکه نفهم', 'martike nafahm', 'Du Begriffsstutziger', 607, 'گفتن «نفهم» به دیگران بی‌ادبی است.', 'Andere „begriffsstutzig" zu nennen ist unhöflich.', NULL, 3),
  ('پدر سوخته', 'pedar-sukhte', 'Schlingel / Schlitzohr', 607, '«پدر سوخته» اغلب شوخی و محبت‌آمیز برای بچه‌ی شیطان است.', '„Pedar-sukhte" ist oft scherzhaft-liebevoll für ein freches Kind.', 'wörtl. „verbrannter Vater“', 3),
  ('پدر سگ', 'pedar-sag', 'Schimpfwort', 607, '«پدر سگ» گاهی شوخی و گاهی دشنام است؛ با احتیاط.', '„Pedar-sag" ist mal scherzhaft, mal Schimpfwort; mit Vorsicht zu verwenden.', 'wörtl. „Hundevater“', 3),
  ('پفیوز', 'pofyuz', 'Nichtsnutz / willenlos', 607, '«پفیوز» دشنامی زننده است.', '„Nichtsnutz" ist ein anstößiges Schimpfwort.', 'vulgär', 3),
  ('چه خاکی به سرم بریزم', 'che khâki be saram berizam', 'Was soll ich nur tun! (verzweifelt)', 607, 'وقتی کسی درمانده است می‌گوید «چه خاکی به سرم بریزم».', 'Wenn jemand verzweifelt ist, sagt er „Was soll ich nur tun".', NULL, 3),
  ('چه غلطا', 'che ghalatâ', 'Was erlaubst du dir!', 607, '«چه غلطا» عبارتی تند و گله‌مندانه است.', '„Was erlaubst du dir" ist ein scharfer, vorwurfsvoller Ausdruck.', NULL, 3),
  ('کثافت', 'kesâfat', 'Dreckskerl', 607, '«کثافت» دشنامی شدید است.', '„Dreckskerl" ist ein heftiges Schimpfwort.', NULL, 3),
  ('کون گشاد', 'kun goshâd', 'Faulpelz', 607, '«کون گشاد» اصطلاحی عامیانه و بی‌ادبانه برای آدم تنبل است.', 'Dieser derbe Ausdruck steht umgangssprachlich für einen faulen Menschen.', 'vulgär', 3),
  ('گمشو', 'gomsho', 'Hau ab / Verschwinde', 607, '«گمشو» دستوری خشن و توهین‌آمیز است.', '„Hau ab" ist ein grober, beleidigender Befehl.', NULL, 3),
  ('گه خوردی', 'goh khordi', 'du hast was Falsches gesagt', 607, 'این عبارت بسیار رکیک است و نباید به کار رود.', 'Dieser Ausdruck ist sehr vulgär und sollte nicht verwendet werden.', 'sehr vulgär, wörtl. „du hast Sch… gegessen“', 3)
